#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BS 16
#define AA(_i,_j) a[(offset)*size+(_i)*size+(_j)+(offset)]
#define BB(_i,_j) a[(_i)*size+(_j)]

__kernel void lud_diagonal(__global float* a, __local float* shared_mem, int size, int offset)
{
    int i = get_global_id(0);
    if (i >= BS) return;

    int j, k;

    for (j = i; j < BS; j++) {
        for (k = 0; k < i; k++) {
            AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
        }
    }

    float temp = 1.f / AA(i,i);
    for (j = i+1; j < BS; j++) {
        for (k = 0; k < i; k++) {
            AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
        }
        AA(j,i) = AA(j,i) * temp;
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp1, __local float* temp2, __local float* temp3, int size, int offset)
{
    int chunk_idx = get_global_id(0);

    int chunks_in_inter_row = (size - offset - BS) / BS;
    if (chunk_idx >= chunks_in_inter_row) return;

    int i, j, k;
    int i_global = offset;
    int j_global = offset;

    // Copy block from a to temp1
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp1[i*BS + j] = a[size*(i + offset) + offset + j];
        }
    }

    j_global += BS * (chunk_idx + 1);

    // Update perimeter row
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            float sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp1[i*BS + k] * BB(i_global + k, j_global + j);
            }
            BB(i_global + i, j_global + j) = BB(i_global + i, j_global + j) - sum;
        }
    }

    j_global = offset;
    i_global += BS * (chunk_idx + 1);

    // Update perimeter column
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            float sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += BB(i_global + i, j_global + k) * temp1[k*BS + j];
            }
            a[size*(i_global + i) + j_global + j] = (a[size*(i_global + i) + j_global + j] - sum) / a[size*(offset + j) + offset + j];
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, int size, int offset)
{
    int gid_x = get_global_id(0);
    int gid_y = get_global_id(1);

    int chunks_in_inter_row = (size - offset - BS) / BS;
    if (gid_x >= chunks_in_inter_row || gid_y >= chunks_in_inter_row) return;

    int i, j, k;
    int i_global = offset + BS * (1 + gid_y);
    int j_global = offset + BS * (1 + gid_x);

    // Copy top and left blocks
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_top[i*BS + j] = a[size*(i + offset) + j + j_global];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }

    // Compute sum and update internal block
    for (i = 0; i < BS; i++) {
        float sum[BS];
        for (j = 0; j < BS; j++) sum[j] = 0.f;

        for (k = 0; k < BS; k++) {
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left[i*BS + k] * temp_top[k*BS + j];
            }
        }
        for (j = 0; j < BS; j++) {
            BB(i + i_global, j + j_global) -= sum[j];
        }
    }
}
